const cmd = $('Extract Command1').first().json.command;
const chatId = $('Extract Command1').first().json.chatId;
const output = ($json.stdout || $json.text || '').trim() || 'No output';
const labels = {
  '/disk': '💾 Disk Space',
  '/containers': '🐳 Containers',
  '/cpu': '🌡️ CPU',
  '/memory': '🧠 Memory',
  '/uptime': '⏱️ Uptime',
  '/top': '📊 Top Processes',
  '/ip': '🌐 IP Addresses',
  '/ports': '🔌 Open Ports',
  '/vpn': '🔒 WireGuard VPN',
  '/restart': '🔄 Restart',
  '/stop': '🛑 Stop',
  '/start': '▶️ Start',
  '/stopped': '🛑 Stopped Containers',
  '/logins': '🔑 Recent Logins'
};
const label = labels[cmd] || cmd;
return [{ json: { chatId, text: label + '\n```\n' + output + '\n```' } }];

